#!/usr/bin/env bash
set -euo pipefail

# Batch runner for IMOBench pairwise aggregation using results generated by:
#   scripts/run_imobench_batch_sglang.sh
#
# For each configured (size, benchmark file) pair:
# 1) Load the latest direct-generation result JSON from SGLang output dir.
# 2) Start old-encoding server and run pairwise aggregation NUM_AGG_RUNS times.
# 3) Start new-encoding server and run pairwise aggregation NUM_AGG_RUNS times
#    with the new-encoding prompt template.
#
# Model spec format:
#   size|gen_model_name|agg_orig_model_path|agg_orig_model_name|agg_new_model_path|agg_new_model_name
#
#   gen_model_name        – name of the model used for first-turn generation
#                           (only used to locate existing result files)
#   agg_orig_model_*      – old-encoding model used for aggregation
#   agg_new_model_*       – new-encoding model used for aggregation
#
# Usage:
#   1) Edit FILES and MODEL_SPECS below.
#   2) Run:
#      bash scripts/run_imobench_batch_sglang_with_aggregation.sh

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"

# -----------------------------
# User configuration
# -----------------------------
FILES=(
  "/storage/openpsi/users/zzy/attn-new/AIME25.json"
  "/storage/openpsi/users/zzy/attn-new/AIME24.json"
)

MODEL_SPECS=(
  # size|gen_model_name|agg_orig_path|agg_orig_name|agg_new_path|agg_new_name
  "4b|qwen3-4b|/storage/openpsi/models/Qwen__Qwen3-4B|qwen3-4b|/storage/openpsi/users/zzy/train_new_encoding/Multiverse/ckpts/Qwen3Chunked-20260418_145450|qwen3-4b-newenc"
#   "8b|qwen3-8b|/storage/openpsi/models/Qwen__Qwen3-8B|qwen3-8b|/storage/openpsi/models/zzy/Qwen__Qwen3-8B-new-tok|qwen3-8b-newenc"
#   "30b|qwen3-30b-a3b|/storage/openpsi/models/Qwen__Qwen3-30B-A3B|qwen3-30b-a3b|/storage/openpsi/models/zzy/Qwen__Qwen3-30B-A3B-new-tok|qwen3-30b-a3b-newenc"
)

# Directory where run_imobench_batch_sglang.sh writes rollouts.
SGLANG_RESULT_BASE_DIR="$ROOT_DIR/results/test_time_compute"

SERVER_HOST="0.0.0.0"
SERVER_PORT=8000
TENSOR_PARALLEL_SIZE=8
SERVER_STARTUP_TIMEOUT=300
OLD_CONTEXT_LEN=40000

# New-encoding server settings (from README-new.md latest encoding section).
NEW_ENV_ACTIVATE="/storage/openpsi/users/zzy/.zzy-enc-2/bin/activate"
NEW_USE_TRUST_REMOTE_CODE=true
NEW_HF_OVERRIDES='{"architectures": ["Qwen3ChunkedForCausalLM"], "chunk_start_token_id": 151669, "chunk_end_token_id": 151670}'

MAX_CONCURRENT_AGG=40
NUM_AGG_RUNS=8

OLD_PAIRWISE_TEMPLATE="aggregation_pairwise_comparison"
NEW_PAIRWISE_TEMPLATE="aggregation_pairwise_new_encoding_comparison"

RESUME=false
RESUME_FROM=""

SERVER_PID=""
SUMMARY_ROWS=()

usage() {
  cat <<'EOF'
Usage:
  bash scripts/run_imobench_batch_sglang_with_aggregation.sh [optional flags]

Configuration:
  Edit FILES and MODEL_SPECS directly in this script.

Optional flags:
  --result-base-dir         Base dir of SGLang direct-generation outputs
                            (default: results/test_time_compute)
  --max-concurrent-agg      Max concurrent problems for aggregation (default: 40)
  --num-agg-runs            Number of aggregation runs to average (default: 8)
  --resume                  Enable resume mode for aggregation
  --resume-from FILE        Resume from specific result file where supported

  --host                    Service bind host (default: 0.0.0.0)
  --port                    Service port (default: 8000)
  --tensor-parallel-size    Tensor parallel size (default: 8)
  --server-startup-timeout  Seconds to wait for readiness (default: 300)
  --old-context-len         --max-model-len for old-encoding vllm serve (default: 40000)

  --new-hf-overrides JSON   hf-overrides passed to new-encoding api_server
  --new-env-activate PATH   Activation script path for new-encoding env
                            (default: /storage/openpsi/users/zzy/.zzy-enc-2/bin/activate)
  --new-no-trust-remote-code Disable --trust-remote-code for new-encoding server

  -h, --help                Show help
EOF
}

cleanup_server() {
  if [[ -n "$SERVER_PID" ]]; then
    if kill -0 "$SERVER_PID" 2>/dev/null; then
      echo "Stopping server (pid=$SERVER_PID)..."
      kill "$SERVER_PID" 2>/dev/null || true
      wait "$SERVER_PID" 2>/dev/null || true
    fi
    SERVER_PID=""
  fi
}

kill_existing_service_on_port() {
  local pids
  pids="$(lsof -ti tcp:"$SERVER_PORT" 2>/dev/null || true)"
  if [[ -n "$pids" ]]; then
    echo "Killing existing service(s) on port $SERVER_PORT: $pids"
    kill $pids 2>/dev/null || true
    sleep 2
    pids="$(lsof -ti tcp:"$SERVER_PORT" 2>/dev/null || true)"
    if [[ -n "$pids" ]]; then
      echo "Force-killing stubborn service(s) on port $SERVER_PORT: $pids"
      kill -9 $pids 2>/dev/null || true
      sleep 1
    fi
  fi
}

wait_for_server_ready() {
  local start_ts elapsed
  start_ts="$(date +%s)"
  echo "Waiting for service at http://127.0.0.1:${SERVER_PORT}/v1/models ..."

  while true; do
    if curl -fsS "http://127.0.0.1:${SERVER_PORT}/v1/models" >/dev/null 2>&1; then
      echo "Service is ready."
      return 0
    fi

    if [[ -n "$SERVER_PID" ]] && ! kill -0 "$SERVER_PID" 2>/dev/null; then
      echo "Error: service exited before becoming ready." >&2
      return 1
    fi

    elapsed=$(( $(date +%s) - start_ts ))
    if (( elapsed >= SERVER_STARTUP_TIMEOUT )); then
      echo "Error: timed out waiting for service after ${SERVER_STARTUP_TIMEOUT}s." >&2
      return 1
    fi
    sleep 2
  done
}

start_old_server() {
  local model_name="$1"
  local model_path="$2"

  cleanup_server
  kill_existing_service_on_port

  echo "Starting old-encoding server: $model_name -> $model_path"
  (
    cd "$ROOT_DIR"
    vllm serve "$model_path" \
      --host "$SERVER_HOST" \
      --port "$SERVER_PORT" \
      --tensor-parallel-size "$TENSOR_PARALLEL_SIZE" \
      --max-model-len "$OLD_CONTEXT_LEN" \
      --served-model-name "$model_name"
  ) &
  SERVER_PID=$!

  wait_for_server_ready
}

start_new_server() {
  local model_name="$1"
  local model_path="$2"

  cleanup_server
  kill_existing_service_on_port

  echo "Starting new-encoding server: $model_name -> $model_path"
  (
    cd "$ROOT_DIR"

    if [[ ! -f "$NEW_ENV_ACTIVATE" ]]; then
      echo "Error: new-encoding env activation script not found: $NEW_ENV_ACTIVATE" >&2
      exit 1
    fi

    # Keep env switch local to this subshell so aggregation runs in caller env.
    # The server keeps running after deactivation because process env is already set.
    source "$NEW_ENV_ACTIVATE"

    cmd=(
      python -m vllm.entrypoints.openai.api_server
      --host "$SERVER_HOST"
      --port "$SERVER_PORT"
      --model "$model_path"
      --tokenizer "$model_path"
      --served-model-name "$model_name"
      --tensor-parallel-size "$TENSOR_PARALLEL_SIZE"
      --hf-overrides "$NEW_HF_OVERRIDES"
    )

    if [[ "$NEW_USE_TRUST_REMOTE_CODE" == true ]]; then
      cmd+=(--trust-remote-code)
    fi

    "${cmd[@]}" &
    local child_pid="$!"

    deactivate >/dev/null 2>&1 || true

    trap 'kill "$child_pid" 2>/dev/null || true; wait "$child_pid" 2>/dev/null || true' TERM INT EXIT
    wait "$child_pid"
  ) &
  SERVER_PID=$!

  wait_for_server_ready
}

sanitize_name() {
  local raw="$1"
  echo "$raw" | sed 's/[^A-Za-z0-9_-]/_/g'
}

ensure_openai_model_prefix() {
  local model_name="$1"
  if [[ "$model_name" == openai/* ]]; then
    echo "$model_name"
  else
    echo "openai/$model_name"
  fi
}

get_latest_file() {
  local dir="$1"
  local pattern="$2"
  local latest=""

  if [[ ! -d "$dir" ]]; then
    echo ""
    return 0
  fi

  shopt -s nullglob
  local matches=("$dir"/$pattern)
  shopt -u nullglob

  if [[ ${#matches[@]} -eq 0 ]]; then
    echo ""
    return 0
  fi

  latest="$(ls -1t "${matches[@]}" | head -n1)"
  echo "$latest"
}

extract_generation_pass1() {
  local json_file="$1"
  python3 - "$json_file" <<'PY'
import json
import sys

path = sys.argv[1]
with open(path, "r", encoding="utf-8") as f:
    data = json.load(f)

val = data.get("metrics", {}).get("pass@1")
if val is None:
    print("nan")
else:
    print(f"{float(val):.6f}")
PY
}

extract_aggregation_pass1() {
  local json_file="$1"
  python3 - "$json_file" <<'PY'
import json
import sys

path = sys.argv[1]
with open(path, "r", encoding="utf-8") as f:
    data = json.load(f)

val = data.get("aggregate_metrics", {}).get("pass@1")
if val is None:
    print("nan")
else:
    print(f"{float(val):.6f}")
PY
}

average_values() {
  if [[ $# -eq 0 ]]; then
    echo "nan"
    return 0
  fi

  python3 - "$@" <<'PY'
import math
import sys

vals = []
for x in sys.argv[1:]:
    try:
        v = float(x)
    except Exception:
        continue
    if math.isnan(v):
        continue
    vals.append(v)

if not vals:
    print("nan")
else:
    print(f"{sum(vals) / len(vals):.6f}")
PY
}

run_aggregation() {
  local result_file="$1"
  local output_dir="$2"
  local request_model="$3"
  local pairwise_template="$4"

  local cmd=(
    python3 -m scripts.run_aggregation_experiment
    --result-files "$result_file"
    --output-dir "$output_dir"
    --model_name "$request_model"
    --pairwise-template "$pairwise_template"
    --max-concurrent "$MAX_CONCURRENT_AGG"
  )

  if [[ "$RESUME" == true ]]; then
    cmd+=(--resume)
  fi
  if [[ -n "$RESUME_FROM" ]]; then
    cmd+=(--resume-from "$RESUME_FROM")
  fi

  (
    cd "$ROOT_DIR"
    "${cmd[@]}"
  )
}

trap cleanup_server EXIT INT TERM

while [[ $# -gt 0 ]]; do
  case "$1" in
    --result-base-dir)
      SGLANG_RESULT_BASE_DIR="$2"
      shift 2
      ;;
    --max-concurrent-agg)
      MAX_CONCURRENT_AGG="$2"
      shift 2
      ;;
    --num-agg-runs)
      NUM_AGG_RUNS="$2"
      shift 2
      ;;
    --resume)
      RESUME=true
      shift
      ;;
    --resume-from)
      RESUME_FROM="$2"
      shift 2
      ;;
    --host)
      SERVER_HOST="$2"
      shift 2
      ;;
    --port)
      SERVER_PORT="$2"
      shift 2
      ;;
    --tensor-parallel-size)
      TENSOR_PARALLEL_SIZE="$2"
      shift 2
      ;;
    --server-startup-timeout)
      SERVER_STARTUP_TIMEOUT="$2"
      shift 2
      ;;
    --old-context-len)
      OLD_CONTEXT_LEN="$2"
      shift 2
      ;;
    --new-hf-overrides)
      NEW_HF_OVERRIDES="$2"
      shift 2
      ;;
    --new-env-activate)
      NEW_ENV_ACTIVATE="$2"
      shift 2
      ;;
    --new-no-trust-remote-code)
      NEW_USE_TRUST_REMOTE_CODE=false
      shift
      ;;
    -h|--help)
      usage
      exit 0
      ;;
    *)
      echo "Unknown argument: $1" >&2
      usage
      exit 1
      ;;
  esac
done

if [[ ${#FILES[@]} -eq 0 ]]; then
  echo "Error: FILES is empty. Edit this script and set FILES in the user configuration section." >&2
  usage
  exit 1
fi

if [[ ${#MODEL_SPECS[@]} -eq 0 ]]; then
  echo "Error: MODEL_SPECS is empty. Edit this script and set MODEL_SPECS in the user configuration section." >&2
  usage
  exit 1
fi

if ! [[ "$NUM_AGG_RUNS" =~ ^[0-9]+$ ]] || [[ "$NUM_AGG_RUNS" -le 0 ]]; then
  echo "Error: NUM_AGG_RUNS must be a positive integer, got: $NUM_AGG_RUNS" >&2
  exit 1
fi

if [[ "$OLD_PAIRWISE_TEMPLATE" == "$NEW_PAIRWISE_TEMPLATE" ]]; then
  echo "Error: old/new pairwise templates must differ. Got: $OLD_PAIRWISE_TEMPLATE" >&2
  exit 1
fi

for file in "${FILES[@]}"; do
  if [[ ! -f "$file" ]]; then
    echo "Error: input file not found: $file" >&2
    exit 1
  fi
done

export OPENAI_API_BASE="http://127.0.0.1:${SERVER_PORT}/v1"
export LLM_CONTEXT_LIMIT_TOKENS="$OLD_CONTEXT_LEN"
if [[ -z "${OPENAI_API_KEY:-}" ]]; then
  export OPENAI_API_KEY="dummy"
fi

TIMESTAMP="$(date +%Y%m%d_%H%M%S)"
SUMMARY_DIR="$ROOT_DIR/results/test_time_compute/sglang_batch_with_aggregation"
mkdir -p "$SUMMARY_DIR"
SUMMARY_CSV="$SUMMARY_DIR/summary_${TIMESTAMP}.csv"

echo "size,test_file,encoding,generation_pass_at_1,aggregation_pairwise_pass_at_1_avg,aggregation_runs,generation_result_file,aggregation_output_dir" > "$SUMMARY_CSV"

echo "========================================"
echo "IMOBench SGLang result aggregation batch"
echo "========================================"
echo "Files: ${#FILES[@]}"
echo "Model specs: ${#MODEL_SPECS[@]}"
echo "SGLang result base dir: $SGLANG_RESULT_BASE_DIR"
echo "Agg max concurrent: $MAX_CONCURRENT_AGG"
echo "Aggregation runs per setting: $NUM_AGG_RUNS"
echo "Server host: $SERVER_HOST"
echo "Server port: $SERVER_PORT"
echo "Tensor parallel size: $TENSOR_PARALLEL_SIZE"
echo "Server startup timeout: $SERVER_STARTUP_TIMEOUT"
echo "Old context length: $OLD_CONTEXT_LEN"
echo "Old template: $OLD_PAIRWISE_TEMPLATE"
echo "New template: $NEW_PAIRWISE_TEMPLATE"
echo "Resume mode: $RESUME"
if [[ -n "$RESUME_FROM" ]]; then
  echo "Resume from: $RESUME_FROM"
fi
echo "========================================"

for spec in "${MODEL_SPECS[@]}"; do
  IFS='|' read -r SIZE GEN_MODEL_NAME ORIG_PATH ORIG_NAME NEW_PATH NEW_NAME <<< "$spec"

  if [[ -z "${SIZE:-}" || -z "${GEN_MODEL_NAME:-}" || -z "${ORIG_PATH:-}" || -z "${ORIG_NAME:-}" || -z "${NEW_PATH:-}" || -z "${NEW_NAME:-}" ]]; then
    echo "Error: invalid model spec '$spec'" >&2
    echo "Expected: size|gen_model_name|agg_orig_model_path|agg_orig_model_name|agg_new_model_path|agg_new_model_name" >&2
    exit 1
  fi

  ORIG_REQUEST_MODEL="$(ensure_openai_model_prefix "$ORIG_NAME")"
  NEW_REQUEST_MODEL="$(ensure_openai_model_prefix "$NEW_NAME")"
  GEN_ALIAS_SANITIZED="$(sanitize_name "$GEN_MODEL_NAME")"

  echo
  echo "========================================"
  echo "Model size: $SIZE"
  echo "Generation model (for result lookup): $GEN_MODEL_NAME"
  echo "Aggregation old-encoding model: $ORIG_NAME -> $ORIG_PATH"
  echo "Aggregation new-encoding model: $NEW_NAME -> $NEW_PATH"
  echo "========================================"

  for file in "${FILES[@]}"; do
    FILE_STEM="$(basename "$file")"
    FILE_STEM="${FILE_STEM%.*}"
    BENCH_LABEL="$(sanitize_name "$FILE_STEM")"
    BENCH_NAME="imobench_${BENCH_LABEL}"

    GEN_OUTPUT_DIR="$SGLANG_RESULT_BASE_DIR/${BENCH_NAME}_rollouts_${GEN_ALIAS_SANITIZED}"
    GEN_PATTERN="direct_generation_${BENCH_NAME}_${GEN_ALIAS_SANITIZED}_*.json"
    GEN_RESULT_FILE="$(get_latest_file "$GEN_OUTPUT_DIR" "$GEN_PATTERN")"

    if [[ -z "$GEN_RESULT_FILE" ]]; then
      echo "Error: cannot find SGLang direct-generation result under $GEN_OUTPUT_DIR with pattern $GEN_PATTERN" >&2
      exit 1
    fi

    GEN_PASS1="$(extract_generation_pass1 "$GEN_RESULT_FILE")"

    echo
    echo "----------------------------------------"
    echo "Size: $SIZE | File: $file"
    echo "Benchmark label: $BENCH_LABEL"
    echo "Latest generation result: $GEN_RESULT_FILE"
    echo "----------------------------------------"

    # 1) Aggregation with new encoding template/server
    start_new_server "$NEW_NAME" "$NEW_PATH"

    AGG_NEW_OUT_DIR="$SUMMARY_DIR/aggregation/${SIZE}/${BENCH_LABEL}/new"
    mkdir -p "$AGG_NEW_OUT_DIR"
    AGG_NEW_RUN_VALUES=()

    for ((run_idx=1; run_idx<=NUM_AGG_RUNS; run_idx++)); do
      echo "Running new-encoding aggregation ${run_idx}/${NUM_AGG_RUNS} ..."
      run_aggregation "$GEN_RESULT_FILE" "$AGG_NEW_OUT_DIR" "$NEW_REQUEST_MODEL" "$NEW_PAIRWISE_TEMPLATE"

      AGG_NEW_RESULT_FILE="$(get_latest_file "$AGG_NEW_OUT_DIR" "aggregation_experiment_pairwise_comparison_${BENCH_NAME}_*.json")"
      if [[ -z "$AGG_NEW_RESULT_FILE" ]]; then
        echo "Error: cannot find new-encoding aggregation result under $AGG_NEW_OUT_DIR" >&2
        exit 1
      fi
      AGG_NEW_RUN_PASS1="$(extract_aggregation_pass1 "$AGG_NEW_RESULT_FILE")"
      AGG_NEW_RUN_VALUES+=("$AGG_NEW_RUN_PASS1")
    done
    AGG_NEW_PASS1_AVG="$(average_values "${AGG_NEW_RUN_VALUES[@]}")"

    # 2) Aggregation with old encoding template/server
    start_old_server "$ORIG_NAME" "$ORIG_PATH"

    AGG_OLD_OUT_DIR="$SUMMARY_DIR/aggregation/${SIZE}/${BENCH_LABEL}/old"
    mkdir -p "$AGG_OLD_OUT_DIR"
    AGG_OLD_RUN_VALUES=()

    for ((run_idx=1; run_idx<=NUM_AGG_RUNS; run_idx++)); do
      echo "Running old-encoding aggregation ${run_idx}/${NUM_AGG_RUNS} ..."
      run_aggregation "$GEN_RESULT_FILE" "$AGG_OLD_OUT_DIR" "$ORIG_REQUEST_MODEL" "$OLD_PAIRWISE_TEMPLATE"

      AGG_OLD_RESULT_FILE="$(get_latest_file "$AGG_OLD_OUT_DIR" "aggregation_experiment_pairwise_comparison_${BENCH_NAME}_*.json")"
      if [[ -z "$AGG_OLD_RESULT_FILE" ]]; then
        echo "Error: cannot find old-encoding aggregation result under $AGG_OLD_OUT_DIR" >&2
        exit 1
      fi
      AGG_OLD_RUN_PASS1="$(extract_aggregation_pass1 "$AGG_OLD_RESULT_FILE")"
      AGG_OLD_RUN_VALUES+=("$AGG_OLD_RUN_PASS1")
    done
    AGG_OLD_PASS1_AVG="$(average_values "${AGG_OLD_RUN_VALUES[@]}")"

    SUMMARY_ROWS+=("$SIZE|$file|$GEN_PASS1|new|$AGG_NEW_PASS1_AVG|$GEN_RESULT_FILE|$AGG_NEW_OUT_DIR")
    SUMMARY_ROWS+=("$SIZE|$file|$GEN_PASS1|old|$AGG_OLD_PASS1_AVG|$GEN_RESULT_FILE|$AGG_OLD_OUT_DIR")

    echo "$SIZE,$file,new,$GEN_PASS1,$AGG_NEW_PASS1_AVG,$NUM_AGG_RUNS,$GEN_RESULT_FILE,$AGG_NEW_OUT_DIR" >> "$SUMMARY_CSV"
    echo "$SIZE,$file,old,$GEN_PASS1,$AGG_OLD_PASS1_AVG,$NUM_AGG_RUNS,$GEN_RESULT_FILE,$AGG_OLD_OUT_DIR" >> "$SUMMARY_CSV"

    cleanup_server
  done
done

echo
echo "========================================"
echo "No aggregation accuracies: {size} x {test_file}"
echo "========================================"
for row in "${SUMMARY_ROWS[@]}"; do
  IFS='|' read -r SIZE FILE GEN_PASS1 ENCODING _ _ _ <<< "$row"
  if [[ "$ENCODING" == "old" ]]; then
    echo "size=$SIZE | file=$FILE | direct_generation_pass@1=$GEN_PASS1"
  fi
done

echo
echo "========================================"
echo "Aggregation accuracies: {size} x {old/new encoding} x {test_file}"
echo "========================================"
for row in "${SUMMARY_ROWS[@]}"; do
  IFS='|' read -r SIZE FILE _ ENCODING AGG_PASS1 _ _ <<< "$row"
  echo "size=$SIZE | encoding=$ENCODING | file=$FILE | pairwise_aggregation_pass@1_avg_over_${NUM_AGG_RUNS}_runs=$AGG_PASS1"
done

echo
echo "Summary CSV saved to: $SUMMARY_CSV"
echo "All runs completed."
